```python
class MeshyClient(Abstract3DGenerationClient):
    def __await_preview_request(
        self,
        data: dict[str, Any],
        prompt: str,
        additional_options: Optional[GenerativeThreeDAdditionalOptions],
    ) -> str:
        if not preview_result.async_response:
            raise MeshyException("Preview request failed.")
        preview_task_id = preview_result.async_response.request_id
